import React from 'react';
import { Card, CardContent, Box, Typography, Stack } from '@mui/material';
import response from './response.json';

interface EstimatedTaxes {
  quarter: string;
  amountOwed: number;
  dueDate: string;
}

interface IncomeBracket {
  bracketRange: string;
  taxRate: number;
}

interface TaxData {
  estimatedTaxes: EstimatedTaxes;
  incomeBracket: IncomeBracket;
}

export default function Widget() {
  const taxData = response.data as TaxData;
  const { estimatedTaxes, incomeBracket } = taxData;
  const { theme, primaryColor, accentColor } = response.meta;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 420, bgcolor: theme === 'light' ? '#FFFFFF' : '#1E293B' }} elevation={2}>
      <CardContent sx={{ p: 2 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="body2" sx={{ color: theme === 'light' ? 'text.secondary' : '#CBD5E1' }}>
              Estimated Taxes for {estimatedTaxes.quarter}
            </Typography>
            <Typography variant="h4" fontWeight={600} sx={{ color: primaryColor }}>
              ${estimatedTaxes.amountOwed.toLocaleString()}
            </Typography>
            <Typography variant="body2" sx={{ color: theme === 'light' ? 'text.secondary' : '#CBD5E1' }}>
              Due by {new Date(estimatedTaxes.dueDate).toLocaleDateString()}
            </Typography>
          </Box>
          <Box>
            <Typography variant="body2" sx={{ color: theme === 'light' ? 'text.secondary' : '#CBD5E1' }}>
              Income Bracket
            </Typography>
            <Typography variant="body1" fontWeight={500} sx={{ color: theme === 'light' ? 'text.secondary' : '#E5E7EB' }}>
              {incomeBracket.bracketRange}
            </Typography>
            <Typography variant="body2" sx={{ color: accentColor }}>
              Tax Rate: {incomeBracket.taxRate}%
            </Typography>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
